  'contact.formMessagePlaceholder': { en: 'How can we help?', ar: 'كيف يمكننا المساعدة؟', zh: '我们能帮您什么？', fr: 'Comment pouvons-nous vous aider ?', ru: 'Как мы можем помочь?', es: '¿Cómo podemos ayudarte?', ta: 'நாங்கள் எப்படி உதவலாம்?', si: 'අපි කෙසේ උදව් කළ හැකිද?' },
  'contact.send': { en: 'Send message', ar: 'إرسال الرسالة', zh: '发送留言', fr: 'Envoyer le message', ru: 'Отправить сообщение', es: 'Enviar mensaje', ta: 'செய்தியை அனுப்பு', si: 'පණිවිඩය යවන්න' },
  'contact.emailLabel': { en: 'Email', ar: 'البريد الإلكتروني', zh: '电子邮箱', fr: 'E-mail', ru: 'Эл. почта', es: 'Correo electrónico', ta: 'மின்னஞ்சல்', si: 'ඊමේල්' },
  'contact.whatsappLabel': { en: 'WhatsApp', ar: 'واتساب', zh: 'WhatsApp', fr: 'WhatsApp', ru: 'WhatsApp', es: 'WhatsApp', ta: 'வாட்ஸ்அப்', si: 'WhatsApp' },
