  'cust.up.kicker': { en: 'Keep the momentum going', ar: 'حافظ على الزخم', zh: '保持势头', fr: "Maintenez l'élan", ru: 'Поддерживайте темп', es: 'Mantén el impulso', ta: 'வேகத்தைத் தொடரவும்', si: 'වෙගය පවත්වා ගන්න' },
  'cust.up.kickerBody': { en: "You've used 23 of 100 applications. Top up or move to a bigger package any time — your profile and history stay exactly as they are.", ar: 'استخدمت 23 من 100 طلب. أعد التعبئة أو انتقل إلى باقة أكبر في أي وقت — يظل ملفك الشخصي وسجلك كما هما.', zh: '您已使用23/100次申请额度。随时可充值或升级至更大套餐——您的资料和历史记录将保持不变。', fr: "Vous avez utilisé 23 candidatures sur 100. Rechargez ou passez à une formule plus grande à tout moment — votre profil et votre historique restent inchangés.", ru: 'Вы использовали 23 из 100 заявок. Пополните баланс или перейдите на больший пакет в любое время — ваш профиль и история останутся как есть.', es: 'Has usado 23 de 100 solicitudes. Recarga o cambia a un paquete mayor en cualquier momento: tu perfil e historial permanecen igual.', ta: '100 இல் 23 விண்ணப்பங்களைப் பயன்படுத்தியுள்ளீர்கள். எந்த நேரத்திலும் நிரப்பவும் அல்லது பெரிய தொகுப்புக்கு மாறவும் — உங்கள் சுயவிவரமும் வரலாறும் அப்படியே இருக்கும்.', si: 'ඔබ 100න් 23ක් අයදුම්පත් භාවිතා කර ඇත. ඕනෑම අවස්ථාවක නැවත පුරවන්න හෝ වඩා විශාල පැකේජයකට මාරු වන්න — ඔබේ පැතිකඩ සහ ඉතිහාසය එලෙසම පවතී.' },
  'cust.up.choosePackage': { en: 'Choose a package', ar: 'اختر باقة', zh: '选择套餐', fr: 'Choisissez une formule', ru: 'Выберите пакет', es: 'Elige un paquete', ta: 'ஒரு தொகுப்பைத் தேர்ந்தெடுக்கவும்', si: 'පැකේජයක් තෝරන්න' },
  'cust.notif.title': { en: 'Notifications', ar: 'الإشعارات', zh: '通知', fr: 'Notifications', ru: 'Уведомления', es: 'Notificaciones', ta: 'அறிவிப்புகள்', si: 'දැනුම්දීම්' },
  'cust.notif.subtitle': { en: 'Updates from your ATG team, newest first.', ar: 'تحديثات من فريق ATG، الأحدث أولًا.', zh: '来自您的ATG团队的最新动态，最新的排在最前。', fr: 'Mises à jour de votre équipe ATG, les plus récentes en premier.', ru: 'Обновления от вашей команды ATG, сначала новые.', es: 'Actualizaciones de tu equipo ATG, las más recientes primero.', ta: 'உங்கள் ATG குழுவிலிருந்து புதுப்பிப்புகள், புதியவை முதலில்.', si: 'ඔබේ ATG කණ්ඩායමෙන් යාවත්කාලීන, අලුත්ම ඒවා මුලින්.' },
  'cust.sup.title': { en: 'Support', ar: 'الدعم', zh: '支持', fr: 'Assistance', ru: 'Поддержка', es: 'Soporte', ta: 'ஆதரவு', si: 'සහාය' },
  'cust.sup.subtitle': { en: 'Message your team. A real person replies within one working day.', ar: 'راسل فريقك. يردّ شخص حقيقي خلال يوم عمل واحد.', zh: '给您的团队发消息。真人将在一个工作日内回复。', fr: 'Contactez votre équipe. Une vraie personne répond dans un délai d\'un jour ouvré.', ru: 'Напишите своей команде. Реальный человек ответит в течение одного рабочего дня.', es: 'Escribe a tu equipo. Una persona real responde en un día laboral.', ta: 'உங்கள் குழுவிற்கு செய்தி அனுப்புங்கள். ஒரு உண்மையான நபர் ஒரு வேலை நாளில் பதிலளிப்பார்.', si: 'ඔබේ කණ්ඩායමට පණිවිඩයක් යවන්න. සැබෑ පුද්ගලයෙකු එක වැඩ දිනක් තුළ පිළිතුරු දෙයි.' },
  'cust.sup.placeholder': { en: 'Type a message…', ar: 'اكتب رسالة…', zh: '输入消息……', fr: 'Tapez un message…', ru: 'Введите сообщение…', es: 'Escribe un mensaje…', ta: 'ஒரு செய்தியை தட்டச்சு செய்யவும்…', si: 'පණිවිඩයක් ටයිප් කරන්න…' },
  'cust.sup.send': { en: 'Send', ar: 'إرسال', zh: '发送', fr: 'Envoyer', ru: 'Отправить', es: 'Enviar', ta: 'அனுப்பு', si: 'යවන්න' },
