  'admin.qc.title': { en: 'QC queue', ar: 'قائمة مراقبة الجودة', zh: '质检队列', fr: 'File de contrôle qualité', ru: 'Очередь контроля качества', es: 'Cola de control de calidad', ta: 'QC வரிசை', si: 'QC පෝලිම' },
  'admin.qc.subtitle': { en: "Applications in drafting or QC. Nothing moves to Applied without a QC Lead's sign-off.", ar: 'طلبات قيد الصياغة أو مراقبة الجودة. لا ينتقل شيء إلى \'مُقدَّم\' دون موافقة قائد مراقبة الجودة.', zh: '正在草拟或质检中的申请。没有质检负责人的签核，不会进入"已申请"状态。', fr: "Candidatures en rédaction ou en contrôle qualité. Rien ne passe au statut Soumis sans la validation d'un responsable QC.", ru: 'Заявки в стадии подготовки или контроля качества. Ничего не переходит в статус "Подано" без подписи руководителя контроля качества.', es: 'Solicitudes en redacción o control de calidad. Nada pasa a Enviada sin la aprobación de un responsable de calidad.', ta: 'வரைவு அல்லது QC இல் உள்ள விண்ணப்பங்கள். QC தலைவரின் ஒப்புதல் இல்லாமல் எதுவும் "விண்ணப்பிக்கப்பட்டது" க்கு நகராது.', si: 'කෙටුම්පත් කිරීමේ හෝ QC හි ඇති අයදුම්පත්. QC ප්‍රධානියාගේ අත්සනකින් තොරව කිසිවක් අයදුම් කළ බවට මාරු නොවේ.' },
  'admin.qc.empty': { en: 'Queue is clear', ar: 'القائمة فارغة', zh: '队列已清空', fr: 'La file est vide', ru: 'Очередь пуста', es: 'La cola está vacía', ta: 'வரிசை தெளிவாக உள்ளது', si: 'පෝලිම පැහැදිලියි' },
  'admin.qc.emptyDesc': { en: 'Nothing is currently in drafting or QC.', ar: 'لا يوجد شيء حاليًا قيد الصياغة أو مراقبة الجودة.', zh: '当前没有处于草拟或质检状态的内容。', fr: "Rien n'est actuellement en rédaction ou en contrôle qualité.", ru: 'Сейчас ничего не находится в подготовке или контроле качества.', es: 'Actualmente no hay nada en redacción o control de calidad.', ta: 'தற்போது வரைவு அல்லது QC இல் எதுவும் இல்லை.', si: 'දැනට කෙටුම්පත් කිරීමේ හෝ QC හි කිසිවක් නැත.' },
  'admin.qc.approveApplied': { en: 'Approve & mark applied', ar: 'الموافقة وتعليمها كمُقدَّمة', zh: '批准并标记为已申请', fr: 'Approuver et marquer comme soumis', ru: 'Одобрить и отметить как поданную', es: 'Aprobar y marcar como enviada', ta: 'அங்கீகரித்து விண்ணப்பிக்கப்பட்டதாகக் குறிக்கவும்', si: 'අනුමත කර අයදුම් කළ බව සටහන් කරන්න' },
  'admin.qc.returnDrafting': { en: 'Return to drafting', ar: 'إعادة إلى الصياغة', zh: '退回草拟', fr: 'Renvoyer en rédaction', ru: 'Вернуть на доработку', es: 'Devolver a redacción', ta: 'வரைவுக்குத் திருப்பவும்', si: 'කෙටුම්පත් කිරීමට ආපසු යවන්න' },
  'admin.qc.approvedApplied': { en: 'Approved & marked applied', ar: 'تمت الموافقة وتعليمها كمُقدَّمة', zh: '已批准并标记为已申请', fr: 'Approuvé et marqué comme soumis', ru: 'Одобрено и отмечено как поданное', es: 'Aprobada y marcada como enviada', ta: 'அங்கீகரிக்கப்பட்டு விண்ணப்பிக்கப்பட்டதாகக் குறிக்கப்பட்டது', si: 'අනුමත කර අයදුම් කළ බව සටහන් කරන ලදී' },
  'admin.qc.returnedDrafting': { en: 'Returned to drafting', ar: 'تمت إعادتها إلى الصياغة', zh: '已退回草拟', fr: 'Renvoyé en rédaction', ru: 'Возвращено на доработку', es: 'Devuelta a redacción', ta: 'வரைவுக்குத் திருப்பப்பட்டது', si: 'කෙටුම්පත් කිරීමට ආපසු යවන ලදී' },
  'admin.pay.title': { en: 'Payments', ar: 'الدفعات', zh: '付款记录', fr: 'Paiements', ru: 'Платежи', es: 'Pagos', ta: 'கட்டணங்கள்', si: 'ගෙවීම්' },
  'admin.pay.subtitle': { en: 'Manual reconciliation · each status change is logged with who and when.', ar: 'تسوية يدوية · يُسجَّل كل تغيير حالة مع من ومتى.', zh: '人工对账 · 每次状态变更均记录操作人和时间。', fr: 'Rapprochement manuel · chaque changement de statut est enregistré avec qui et quand.', ru: 'Ручная сверка · каждое изменение статуса фиксируется с указанием кто и когда.', es: 'Reconciliación manual: cada cambio de estado se registra con quién y cuándo.', ta: 'கைமுறை சரிசெய்தல் · ஒவ்வொரு நிலை மாற்றமும் யார் மற்றும் எப்போது என பதிவு செய்யப்படுகிறது.', si: 'අතින් ප්‍රතිසන්ධානය · සෑම තත්ත්ව වෙනසක්ම කවුරුන් සහ කවදාද යනුවෙන් ලොග් කරනු ලැබේ.' },
