  'admin.pay.markPaid': { en: 'Mark Paid', ar: 'تعليم كمدفوع', zh: '标记为已付款', fr: 'Marquer comme payé', ru: 'Отметить как оплачено', es: 'Marcar como pagado', ta: 'செலுத்தப்பட்டதாகக் குறிக்கவும்', si: 'ගෙවන ලද බව සටහන් කරන්න' },
