  'admin.staff.available': { en: 'Available', ar: 'متاح', zh: '可承接', fr: 'Disponible', ru: 'Доступен', es: 'Disponible', ta: 'கிடைக்கிறது', si: 'ලද හැකි' },
  'admin.notif.title': { en: 'Notification templates', ar: 'قوالب الإشعارات', zh: '通知模板', fr: 'Modèles de notification', ru: 'Шаблоны уведомлений', es: 'Plantillas de notificación', ta: 'அறிவிப்பு வார்ப்புருக்கள்', si: 'දැනුම්දීම් ආකෘති' },
  'admin.notif.subtitle': { en: 'The exact copy sent to users on each event. Variables in {curly braces} are filled at send time.', ar: 'النص الدقيق المُرسل للمستخدمين عند كل حدث. تُملأ المتغيرات بين {أقواس مجعدة} عند الإرسال.', zh: '每个事件发送给用户的确切文本。{花括号} 中的变量会在发送时填充。', fr: 'Le texte exact envoyé aux utilisateurs pour chaque événement. Les variables entre {accolades} sont remplies au moment de l\'envoi.', ru: 'Точный текст, отправляемый пользователям при каждом событии. Переменные в {фигурных скобках} заполняются при отправке.', es: 'El texto exacto enviado a los usuarios en cada evento. Las variables en {llaves} se completan al momento del envío.', ta: 'ஒவ்வொரு நிகழ்விலும் பயனர்களுக்கு அனுப்பப்படும் சரியான உரை. {சுருள் அடைப்புக்குறிகளில்} உள்ள மாறிகள் அனுப்பும் நேரத்தில் நிரப்பப்படும்.', si: 'සෑම සිදුවීමකදීම පරිශීලකයින්ට යවන නිශ්චිත පෙළ. {වෘත්තාකාර වරහන්} තුළ ඇති විචල්‍ය යැවීමේ වේලාවේ පුරවනු ලැබේ.' },
  'admin.export.title': { en: 'Export data', ar: 'تصدير البيانات', zh: '导出数据', fr: 'Exporter les données', ru: 'Экспорт данных', es: 'Exportar datos', ta: 'தரவை ஏக்ஸ்போர்ட் செய்', si: 'දත්ත නිර්යාත කරන්න' },
  'admin.export.subtitle': { en: 'Download operational data as CSV for reporting and reconciliation.', ar: 'تحميل البيانات التشغيلية كـ CSV للتقارير والتسوية.', zh: '下载CSV格式的运营数据用于报告和对账。', fr: 'Téléchargez les données opérationnelles en CSV pour les rapports et le rapprochement.', ru: 'Скачайте операционные данные в формате CSV для отчётности и сверки.', es: 'Descarga datos operativos en CSV para informes y reconciliación.', ta: 'அறிக்கையிடல் மற்றும் சரிசெய்தலுக்கு செயல்பாட்டு தரவை CSV ஆக பதிவிறக்கவும்.', si: 'වාර්තාකරණය සහ ප්‍රතිසන්ධානය සඳහා මෙහෙයුම් දත්ත CSV ලෙස බාගත කරන්න.' },
  'admin.export.download': { en: 'Download', ar: 'تحميل', zh: '下载', fr: 'Télécharger', ru: 'Скачать', es: 'Descargar', ta: 'பதிவிறக்கம்', si: 'බාගත කරන්න' },

