// t(key, lang, vars?) — looks up T[key][lang], falls back to English, then the key itself.
// vars: optional {token: value} map for simple {token} interpolation.
export function translate(key, lang, vars) {
  const entry = T[key]
  let str = entry ? (entry[lang] || entry.en) : key
  if (vars) {
    Object.keys(vars).forEach(k => {
      str = str.replace(new RegExp(`\\{${k}\\}`, 'g'), vars[k])
    })
  }
  return str
}
